define(['jquery','mage/smart-keyboard-handler','mage/mage','domReady!'],function($,keyboardHandler){'use strict';$('.cart-summary').mage('sticky',{container:'#maincontent'});$('.panel.header .top-links-area > .header.links').clone().appendTo('#store\\.links');$('#store\\.links li a').each(function(){var id=$(this).attr('id');if(id!==undefined){$(this).attr('id',id+'_mobile');}});keyboardHandler.apply();$(document).on('click','.yotpo-bottomline .ask-question',function(e){$('#yotpo-tabs-main-widget-tab-1').trigger('click');$('html, body').animate({scrollTop:$('#yotpo-tabs-main-widget-tab-1').offset().top-120},500);});$(document).on('click','.yotpo-sr-bottom-line-summary',function(e){$('#yotpo-tabs-main-widget-tab-0').trigger('click');$('html, body').animate({scrollTop:$('#yotpo-tabs-main-widget-tab-0').offset().top-120},500);});});